render(() => {
    const [modalOpen, setModalOpen] = React.useState(false);

    return (
        <div>
            <Button onClick={() => setModalOpen(true)}>Показать модалку</Button>

            <Stack value={1000}>
                {(zIndex) => (
                    <ModalDesktop
                        zIndex={zIndex}
                        open={modalOpen}
                        onClose={() => setModalOpen(false)}
                    >
                        <ModalDesktop.Content>
                            <style>{`.target {width: 100%}`}</style>
                            <Stack>
                                {(nextZIndex) => (
                                    <Tooltip
                                        zIndex={nextZIndex}
                                        content={<div>Tooltip</div>}
                                        trigger='click'
                                        targetClassName='target'
                                    >
                                        <Button block={true}>Показать тултип</Button>
                                    </Tooltip>
                                )}
                            </Stack>
                        </ModalDesktop.Content>
                    </ModalDesktop>
                )}
            </Stack>
        </div>
    );
});
